#include <stdio.h>
#include <string.h>

#define MSG_SIZE 64
#define QUEUE_LEN 8

// ★ Stage 0 — Exemple complet
typedef struct { long mtype; char mtext[MSG_SIZE]; } MsgBuf;

MsgBuf queue[QUEUE_LEN];
int qtail = 0;

void msgsnd_sim(long type, const char *text) {
    queue[qtail].mtype = type;
    strncpy(queue[qtail].mtext, text, MSG_SIZE - 1);
    qtail++;
}

int msgrcv_typed(MsgBuf *out, long type) {
    for (int i = 0; i < qtail; i++) {
        if (queue[i].mtype == type) {  // ★ filtrer par type
            *out = queue[i];
            // ★ décaler les éléments suivants vers la gauche
            for (int j = i; j < qtail - 1; j++)
                queue[j] = queue[j+1];
            qtail--;                   // ★ réduire la taille
            return 0;
        }
    }
    return -1;  // ★ aucun message de ce type
}

int main(void) {
    msgsnd_sim(1, "normal task");   // ★ type 1
    msgsnd_sim(2, "urgent task");   // ★ type 2
    msgsnd_sim(1, "another task");  // ★ type 1
    MsgBuf msg;
    if (msgrcv_typed(&msg, 2) == 0) // ★ récupérer uniquement type=2
        printf("Found type %ld: %s\n", msg.mtype, msg.mtext);
    return 0;
}

